solution_code:
#include <iostream>

class Vault;

class Inspector {
public:
    void check(const Vault& v);
};

class Vault {
    int m_balance;
public:
    Vault(int balance) : m_balance{ balance } {}
    friend void Inspector::check(const Vault& v);
};

void Inspector::check(const Vault& v) {
    std::cout << "Balance: " << v.m_balance << "\n";
}

int main() {
    int b;
    std::cin >> b;
    Vault vault{ b };
    Inspector inspector;
    inspector.check(vault);
    return 0;
}

