    int t;
    std::cin >> t;
    TempSensor sensor{ t };
    Thermometer therm;
    std::cout << "Reading: " << therm.read(sensor) << "\n";
    return 0;
}

solution_code:
#include <iostream>

class Thermometer;

class TempSensor {
    int m_temp;
public:
    TempSensor(int t) : m_temp{ t } {}
    friend class Thermometer;
};

class Thermometer {
public:
    int read(const TempSensor& s) {
        return s.m_temp;
    }
};

int main() {
    int t;
    std::cin >> t;
    TempSensor sensor{ t };
    Thermometer therm;
    std::cout << "Reading: " << therm.read(sensor) << "\n";
    return 0;
}
